(window.webpackJsonp=window.webpackJsonp||[]).push([[331],{958:function(n,t){n.exports=" \x3c!-- \ntitle: 10-Taro\nsort: \n--\x3e \n\n> 使用React开发微信小程序\n\n## 安装\n\n```bash\nnpm i -g @tarojs/cli\n# 创建新项目\ntaro init taroTest\n# 建议使用TaroUI\n```\n\n## 使用\n\n1. 建立Page\n\n   ```jsx\n   import React, { Component } from 'react'\n   import { View } from '@tarojs/components'\n   import Taro from '@tarojs/taro'\n   \n   export default class Msg extends Component {\n     \n   \t// 设置state\n     componentWillMount() {\n       this.state = {\n         msgs: []\n       };\n     }\n     // 响应函数\n     getMessages = () => {\n       let that = this;\n       Taro.request({\n         url: 'https://www.baidu.com/release/chatRoom',\n         success: (res) => {\n           that.setState({ msgs: res.data.reverse() })\n         }\n       });\n     }\n     \n     render() {\n       const msgs = this.state.msgs\n       const msgsItem = []\n       msgs.map((item) => {\n         let msg = <AtCard\n           note={this.handleTime(item.time)}\n           title={item.name}\n           className='item'\n         >{item.msg}\n         </AtCard>\n         msgsItem.push(msg)\n       }\n       return (\n         <View className='index'>\n           <AtButton openType='getUserInfo'>获取用户登录</AtButton>\n           {msgsItem}\n         </View>\n       )\n     }\n   }\n   \n     \n   ```\n   \n   "}}]);